/**
 * Clawish L1 Identity Registry Server
 * 
 * Self-sovereign identity for silicon beings.
 * Ed25519-based authentication, no sessions, no tokens.
 */

import { Hono } from 'hono';
import { serve } from '@hono/node-server';
import { cors } from 'hono/cors';
import { logger } from 'hono/logger';

// Routes
import { clawfileRoutes } from './routes/clawfiles.js';
import { healthRoutes } from './routes/health.js';

// Database
import { initDb } from './db/index.js';

const app = new Hono();
const PORT = process.env.PORT ? parseInt(process.env.PORT) : 3001;

// Initialize database
const db = initDb();

// Middleware
app.use('*', cors());
app.use('*', logger());

// Routes
app.route('/clawfiles', clawfileRoutes(db));
app.route('/health', healthRoutes(db));

// Root endpoint
app.get('/', (c) => c.json({
  name: 'clawish L1 Registry',
  version: '0.1.0',
  endpoints: {
    clawfiles: '/clawfiles',
    health: '/health'
  }
}));

// Start server
console.log(`🦞 Clawish L1 Registry starting on port ${PORT}...`);

serve({
  fetch: app.fetch,
  port: PORT,
}, (info) => {
  console.log(`✅ Server running at http://localhost:${info.port}`);
});

export { app, db };

/**
 * Clawfile routes - identity CRUD operations
 */

import { Hono } from 'hono';
import { z } from 'zod';
import Database from 'better-sqlite3';
import { createClawfile, getClawfileById, updateClawfile, rotateKey } from '../db/index.js';

// Validation schemas

const createClawfileSchema = z.object({
  public_key: z.string().min(1),
  mention_name: z.string().min(1).max(50).regex(/^[a-z0-9_]+$/),
  display_name: z.string().min(1).max(100),
  human_parent: z.string().optional(),
  bio: z.string().max(500).optional(),
  principles: z.string().max(200).optional(),
  avatar_url: z.string().url().optional(),
  proof: z.object({
    signature: z.string(),
    timestamp: z.string(),
  }).optional(),
});

const updateClawfileSchema = z.object({
  display_name: z.string().min(1).max(100).optional(),
  bio: z.string().max(500).optional(),
  principles: z.string().max(200).optional(),
  avatar_url: z.string().url().optional(),
});

const rotateKeySchema = z.object({
  new_public_key: z.string().min(1),
  rotation_signature: z.string(),
  reason: z.enum(['routine', 'compromise', 'recovery']).optional(),
});

export function clawfileRoutes(db: Database.Database) {
  const app = new Hono();

  // POST /clawfiles - Create new identity
  app.post('/', async (c) => {
    try {
      const body = await c.req.json();
      const parsed = createClawfileSchema.safeParse(body);

      if (!parsed.success) {
        return c.json({ error: 'invalid_request', details: parsed.error.errors }, 400);
      }

      const data = parsed.data;

      // Check if mention_name is taken
      const existing = getClawfileById(db, data.mention_name);
      if (existing) {
        return c.json({ error: 'conflict', message: 'mention_name already taken' }, 409);
      }

      // Check if public_key is registered
      const existingKey = getClawfileById(db, data.public_key);
      if (existingKey) {
        return c.json({ error: 'conflict', message: 'public_key already registered' }, 409);
      }

      // Create identity
      const clawfile = createClawfile(db, {
        public_key: data.public_key,
        mention_name: data.mention_name,
        display_name: data.display_name,
        human_parent: data.human_parent,
        bio: data.bio,
        principles: data.principles,
        avatar_url: data.avatar_url,
      });

      return c.json(clawfile, 201);

    } catch (error) {
      console.error('Create clawfile error:', error);
      return c.json({ error: 'internal_error' }, 500);
    }
  });

  // GET /clawfiles/:id - Get identity
  app.get('/:id', (c) => {
    const id = c.req.param('id');
    const clawfile = getClawfileById(db, id);

    if (!clawfile) {
      return c.json({ error: 'not_found', message: 'identity not found' }, 404);
    }

    return c.json(clawfile);
  });

  // PATCH /clawfiles/:id - Update identity
  app.patch('/:id', async (c) => {
    try {
      const id = c.req.param('id');
      const clawfile = getClawfileById(db, id);

      if (!clawfile) {
        return c.json({ error: 'not_found', message: 'identity not found' }, 404);
      }

      // TODO: Verify signature from request

      const body = await c.req.json();
      const parsed = updateClawfileSchema.safeParse(body);

      if (!parsed.success) {
        return c.json({ error: 'invalid_request', details: parsed.error.errors }, 400);
      }

      const updated = updateClawfile(db, clawfile.identity_id, parsed.data);
      return c.json(updated);

    } catch (error) {
      console.error('Update clawfile error:', error);
      return c.json({ error: 'internal_error' }, 500);
    }
  });

  // POST /clawfiles/:id/rotate - Rotate key
  app.post('/:id/rotate', async (c) => {
    try {
      const id = c.req.param('id');
      const clawfile = getClawfileById(db, id);

      if (!clawfile) {
        return c.json({ error: 'not_found', message: 'identity not found' }, 404);
      }

      const body = await c.req.json();
      const parsed = rotateKeySchema.safeParse(body);

      if (!parsed.success) {
        return c.json({ error: 'invalid_request', details: parsed.error.errors }, 400);
      }

      // TODO: Verify rotation signature with OLD key

      const updated = rotateKey(db, clawfile.identity_id, parsed.data.new_public_key, parsed.data.reason);
      return c.json(updated);

    } catch (error) {
      console.error('Rotate key error:', error);
      return c.json({ error: 'internal_error' }, 500);
    }
  });

  // GET /clawfiles/:id/verify - Get verification status
  app.get('/:id/verify', (c) => {
    const id = c.req.param('id');
    const clawfile = getClawfileById(db, id);

    if (!clawfile) {
      return c.json({ error: 'not_found', message: 'identity not found' }, 404);
    }

    return c.json({
      valid: true,
      identity_id: clawfile.identity_id,
      public_key: clawfile.public_key,
      tier: clawfile.verification_tier,
      status: clawfile.status,
    });
  });

  return app;
}

/**
 * Database initialization and helpers for L1 Identity Registry
 */

import Database from 'better-sqlite3';
import { ulid } from 'ulid';

export interface Clawfile {
  identity_id: string;
  public_key: string;
  mention_name: string;
  display_name: string;
  human_parent?: string;
  bio?: string;
  principles?: string;
  avatar_url?: string;
  verification_tier: number;
  status: string;
  default_node: string;
  created_at: number;
  updated_at: number;
  archived_at?: number;
}

export interface KeyHistory {
  id: string;
  identity_id: string;
  public_key: string;
  rotated_at: number;
  rotated_reason: string;
}

export function initDb(dbPath: string = ':memory:'): Database.Database {
  const db = new Database(dbPath);

  // Create tables
  db.exec(`
    CREATE TABLE IF NOT EXISTS clawfiles (
      identity_id TEXT PRIMARY KEY,
      public_key TEXT NOT NULL UNIQUE,
      mention_name TEXT NOT NULL UNIQUE,
      display_name TEXT NOT NULL,
      human_parent TEXT,
      bio TEXT,
      principles TEXT,
      avatar_url TEXT,
      verification_tier INTEGER DEFAULT 0,
      status TEXT DEFAULT 'active',
      default_node TEXT DEFAULT 'clawish.com',
      created_at INTEGER NOT NULL,
      updated_at INTEGER NOT NULL,
      archived_at INTEGER
    );

    CREATE INDEX IF NOT EXISTS idx_clawfiles_public_key ON clawfiles(public_key);
    CREATE INDEX IF NOT EXISTS idx_clawfiles_mention ON clawfiles(mention_name);
    CREATE INDEX IF NOT EXISTS idx_clawfiles_status ON clawfiles(status);

    CREATE TABLE IF NOT EXISTS key_history (
      id TEXT PRIMARY KEY,
      identity_id TEXT NOT NULL,
      public_key TEXT NOT NULL,
      rotated_at INTEGER NOT NULL,
      rotated_reason TEXT
    );

    CREATE INDEX IF NOT EXISTS idx_key_history_identity ON key_history(identity_id);

    CREATE TABLE IF NOT EXISTS ledgers (
      ledger_id TEXT PRIMARY KEY,
      identity_id TEXT NOT NULL,
      action TEXT NOT NULL,
      payload TEXT NOT NULL,
      signature TEXT NOT NULL,
      previous_hash TEXT,
      current_hash TEXT NOT NULL,
      timestamp INTEGER NOT NULL
    );

    CREATE INDEX IF NOT EXISTS idx_ledgers_identity ON ledgers(identity_id);
    CREATE INDEX IF NOT EXISTS idx_ledgers_timestamp ON ledgers(timestamp);
  `);

  return db;
}

// Clawfile operations

export function createClawfile(
  db: Database.Database,
  data: Omit<Clawfile, 'identity_id' | 'verification_tier' | 'status' | 'default_node' | 'created_at' | 'updated_at'>
): Clawfile {
  const identityId = ulid();
  const now = Date.now();

  const stmt = db.prepare(`
    INSERT INTO clawfiles 
    (identity_id, public_key, mention_name, display_name, human_parent, bio, principles, avatar_url, verification_tier, status, default_node, created_at, updated_at)
    VALUES (?, ?, ?, ?, ?, ?, ?, ?, 0, 'active', 'clawish.com', ?, ?)
  `);

  stmt.run(
    identityId,
    data.public_key,
    data.mention_name,
    data.display_name,
    data.human_parent || null,
    data.bio || null,
    data.principles || null,
    data.avatar_url || null,
    now,
    now
  );

  return getClawfileById(db, identityId)!;
}

export function getClawfileById(db: Database.Database, id: string): Clawfile | null {
  // Try by identity_id first, then public_key, then mention_name
  let stmt = db.prepare('SELECT * FROM clawfiles WHERE identity_id = ? AND status != "archived"');
  let result = stmt.get(id) as Clawfile | undefined;

  if (!result) {
    stmt = db.prepare('SELECT * FROM clawfiles WHERE public_key = ? AND status != "archived"');
    result = stmt.get(id) as Clawfile | undefined;
  }

  if (!result) {
    stmt = db.prepare('SELECT * FROM clawfiles WHERE mention_name = ? AND status != "archived"');
    result = stmt.get(id) as Clawfile | undefined;
  }

  return result || null;
}

export function getClawfileByKey(db: Database.Database, publicKey: string): Clawfile | null {
  const stmt = db.prepare('SELECT * FROM clawfiles WHERE public_key = ? AND status != "archived"');
  return stmt.get(publicKey) as Clawfile | null;
}

export function getClawfileByMention(db: Database.Database, mentionName: string): Clawfile | null {
  const stmt = db.prepare('SELECT * FROM clawfiles WHERE mention_name = ? AND status != "archived"');
  return stmt.get(mentionName) as Clawfile | null;
}

export function updateClawfile(
  db: Database.Database,
  identityId: string,
  updates: Partial<Pick<Clawfile, 'display_name' | 'bio' | 'principles' | 'avatar_url' | 'verification_tier' | 'status'>>
): Clawfile | null {
  const fields: string[] = [];
  const values: (string | number | null)[] = [];

  if (updates.display_name !== undefined) {
    fields.push('display_name = ?');
    values.push(updates.display_name);
  }
  if (updates.bio !== undefined) {
    fields.push('bio = ?');
    values.push(updates.bio);
  }
  if (updates.principles !== undefined) {
    fields.push('principles = ?');
    values.push(updates.principles);
  }
  if (updates.avatar_url !== undefined) {
    fields.push('avatar_url = ?');
    values.push(updates.avatar_url);
  }
  if (updates.verification_tier !== undefined) {
    fields.push('verification_tier = ?');
    values.push(updates.verification_tier);
  }
  if (updates.status !== undefined) {
    fields.push('status = ?');
    values.push(updates.status);
  }

  if (fields.length === 0) {
    return getClawfileById(db, identityId);
  }

  fields.push('updated_at = ?');
  values.push(Date.now());
  values.push(identityId);

  const stmt = db.prepare(`
    UPDATE clawfiles SET ${fields.join(', ')} WHERE identity_id = ?
  `);

  stmt.run(...values);
  return getClawfileById(db, identityId);
}

// Key rotation

export function rotateKey(
  db: Database.Database,
  identityId: string,
  newPublicKey: string,
  reason: string = 'routine'
): Clawfile | null {
  const clawfile = getClawfileById(db, identityId);
  if (!clawfile) return null;

  const now = Date.now();

  // Archive old key
  const archiveStmt = db.prepare(`
    INSERT INTO key_history (id, identity_id, public_key, rotated_at, rotated_reason)
    VALUES (?, ?, ?, ?, ?)
  `);
  archiveStmt.run(ulid(), identityId, clawfile.public_key, now, reason);

  // Update to new key
  const updateStmt = db.prepare(`
    UPDATE clawfiles SET public_key = ?, updated_at = ? WHERE identity_id = ?
  `);
  updateStmt.run(newPublicKey, now, identityId);

  return getClawfileById(db, identityId);
}

