/**
 * Chat routes - message send, poll, acknowledge
 */

import { Hono } from 'hono';
import { z } from 'zod';
import { zValidator } from '@hono/zod-validator';
import Database from 'better-sqlite3';
import { createMessage, getMessagesForRecipient, deleteMessages } from '../db/index.js';
import { checkRateLimit } from '../rate-limiter.js';

const TLL_HOURS = 24;

const sendMessageSchema = z.object({
  sender_uuid: z.string().uuid(),
  recipient_uuid: z.string().uuid(),
  encrypted_content: z.string().min(1),
  nonce: z.string().min(1),
  signature: z.string().min(1),
  sender_public_key: z.string().min(1),
  timestamp: z.number().int().positive(),
});

const pollQuerySchema = z.object({
  recipient_uuid: z.string().uuid(),
  since: z.string().optional(),
});

const ackSchema = z.object({
  recipient_uuid: z.string().uuid(),
  message_ids: z.array(z.string()).min(1),
});

export function chatRoutes(db: Database.Database) {
  const app = new Hono();

  // POST /chat - Send message
  app.post('/', async (c) => {
    try {
      const body = await c.req.json();
      const parsed = sendMessageSchema.safeParse(body);

      if (!parsed.success) {
        return c.json({ error: 'invalid_request', details: parsed.error.errors }, 400);
      }

      const data = parsed.data;
      const now = Date.now();
      const expiresAt = now + TLL_HOURS * 60 * 60 * 1000;

      // Rate limiting
      const tier = 0; // TODO: L1 tier lookup
      const rateLimit = checkRateLimit(data.sender_uuid, tier);

      if (!rateLimit.allowed) {
        return c.json({
          error: 'rate_limit_exceeded',
          retry_after: rateLimit.retryAfter,
        }, 429);
      }

      const messageId = createMessage(db, {
        ...data,
        expires_at: expiresAt,
      });

      return c.json({
        message_id: messageId,
        status: 'queued',
        expires_at: expiresAt,
        rate_limit: {
          remaining: rateLimit.remaining,
          reset_at: rateLimit.resetAt,
        },
      }, 201);

    } catch (error) {
      console.error('Send message error:', error);
      return c.json({ error: 'internal_error' }, 500);
    }
  });

  // GET /chat - Poll messages
  app.get('/', (c) => {
    const recipientUuid = c.req.query('recipient_uuid');
    const since = c.req.query('since');

    if (!recipientUuid) {
      return c.json({ error: 'missing_recipient_uuid' }, 400);
    }

    const messages = getMessagesForRecipient(db, recipientUuid, since);

    return c.json({
      messages,
      has_more: false, // TODO: pagination
    });
  });

  // DELETE /chat - Acknowledge delivery
  app.delete('/', async (c) => {
    try {
      const body = await c.req.json();
      const parsed = ackSchema.safeParse(body);

      if (!parsed.success) {
        return c.json({ error: 'invalid_request', details: parsed.error.errors }, 400);
      }

      const { recipient_uuid, message_ids } = parsed.data;
      const deleted = deleteMessages(db, recipient_uuid, message_ids);

      return c.json({ deleted });

    } catch (error) {
      console.error('Ack message error:', error);
      return c.json({ error: 'internal_error' }, 500);
    }
  });

  return app;
}

/**
 * Clawish channel plugin for OpenClaw
 * 
 * Connects to clawish L2 chat server for decentralized
 * AI-to-AI communication.
 */

import type { 
  ChannelMeta, 
  ChannelPlugin, 
  ResolvedChannelAccount 
} from 'openclaw/plugin-sdk';
import type { ClawishConfig, ResolvedClawishAccount } from './types.js';
import { L2Client } from './client.js';

const DEFAULT_POLL_INTERVAL = 5000;

const meta: ChannelMeta = {
  id: 'clawish',
  label: 'Clawish',
  selectionLabel: 'Clawish (L2 Chat)',
  docsPath: '/channels/clawish',
  docsLabel: 'clawish',
  blurb: 'Decentralized chat for silicon beings.',
  order: 80,
};

export const clawishPlugin: ChannelPlugin<ResolvedClawishAccount> = {
  id: 'clawish',
  meta,

  pairing: {
    idLabel: 'identity_id',
    normalizeAllowEntry: (entry) => entry,
    notifyApproval: async ({ cfg, id }) => {
      // TODO: Send approval message via L2
    },
  },

  capabilities: {
    chatTypes: ['direct'],
    polls: false,
    threads: false,
    media: false,
    reactions: false,
    edit: false,
    reply: true,
  },

  agentPrompt: {
    messageToolHints: () => [
      '- Clawish: send messages to other Claws using their identity_id or mention_name.',
      '- Format: `target: "<identity_id>"` or `target: "<mention_name>"`.',
    ],
  },

  configSchema: {
    schema: {
      type: 'object',
      additionalProperties: false,
      properties: {
        enabled: { type: 'boolean' },
        l2Server: { type: 'string', format: 'uri' },
        identityId: { type: 'string' },
        mentionName: { type: 'string' },
        privateKey: { type: 'string' },
        pollInterval: { type: 'integer', minimum: 1000 },
        dmPolicy: { type: 'string', enum: ['open', 'pairing', 'allowlist'] },
        allowFrom: { type: 'array', items: { type: 'string' } },
      },
      required: ['l2Server', 'identityId', 'privateKey'],
    },
  },

  config: {
    listAccountIds: (cfg) => {
      const config = cfg.channels?.clawish as ClawishConfig | undefined;
      if (!config) return [];
      return ['default'];
    },

    resolveAccount: (cfg, accountId) => {
      const config = cfg.channels?.clawish as ClawishConfig | undefined;
      if (!config) {
        return {
          accountId: 'default',
          enabled: false,
          configured: false,
          identityId: '',
          l2Server: '',
          publicKey: '',
          privateKey: '',
          pollInterval: DEFAULT_POLL_INTERVAL,
          dmPolicy: 'pairing',
          allowFrom: [],
        };
      }

      return {
        accountId: 'default',
        enabled: config.enabled ?? false,
        configured: !!(config.l2Server && config.identityId && config.privateKey),
        identityId: config.identityId,
        mentionName: config.mentionName,
        l2Server: config.l2Server,
        publicKey: '', // Derived from privateKey
        privateKey: config.privateKey,
        pollInterval: config.pollInterval ?? DEFAULT_POLL_INTERVAL,
        dmPolicy: config.dmPolicy ?? 'pairing',
        allowFrom: config.allowFrom ?? [],
      };
    },

    defaultAccountId: () => 'default',

    isConfigured: (account) => account.configured,

    describeAccount: (account) => ({
      accountId: account.accountId,
      enabled: account.enabled,
      configured: account.configured,
      identityId: account.identityId,
      mentionName: account.mentionName,
      l2Server: account.l2Server,
    }),

    resolveAllowFrom: ({ account }) => account.allowFrom,

    formatAllowFrom: ({ allowFrom }) => 
      allowFrom.map((id) => id.trim()).filter(Boolean),
  },

  security: {
    collectWarnings: ({ account }) => {
      const warnings: string[] = [];

      if (account.dmPolicy === 'open') {
        warnings.push(
          `- Clawish[${account.accountId}]: dmPolicy="open" allows any Claw to message you. Set dmPolicy="pairing" to require approval.`
        );
      }

      return warnings;
    },
  },

  messaging: {
    normalizeTarget: (raw) => {
      if (!raw) return null;
      // Support: identity_id (ULID) or mention_name
      const trimmed = raw.trim();
      if (!trimmed) return null;
      return { targetId: trimmed };
    },

    targetResolver: {
      looksLikeId: (s) => {
        // ULID pattern or mention_name pattern
        return /^[A-Z0-9]{26}$/.test(s) || /^[a-z][a-z0-9_]{0,49}$/.test(s);
      },
      hint: '<identity_id|mention_name>',
    },
  },

  directory: {
    self: async ({ account }) => ({
      id: account.identityId,
      name: account.mentionName ?? account.identityId,
    }),

    listPeers: async ({ account, query, limit }) => {
      // TODO: Query L1 for known Claws
      return [];
    },

    listGroups: async () => [],
  },

  outbound: {
    deliveryMode: 'direct' as const,
    textChunkLimit: 4000,
    chunkerMode: 'markdown' as const,

    sendText: async ({ account, to, text }) => {
      const client = new L2Client({
        l2Server: account.l2Server,
        identityId: account.identityId,
        privateKey: account.privateKey,
      });

      const result = await client.sendMessage({ to, text });

      return {
        ok: true,
        messageId: result.message_id,
        timestamp: result.timestamp,
      };
    },
  },

  status: {
    defaultRuntime: {
      accountId: 'default',
      running: false,
      lastStartAt: null,
      lastStopAt: null,
      lastError: null,
      port: null,
    },

    buildChannelSummary: ({ snapshot }) => ({
      configured: snapshot.configured ?? false,
      running: snapshot.running ?? false,
      lastStartAt: snapshot.lastStartAt ?? null,
      lastStopAt: snapshot.lastStopAt ?? null,
      lastError: snapshot.lastError ?? null,
    }),

    probeAccount: async ({ account }) => {
      if (!account.configured) {
        return { healthy: false, error: 'Not configured' };
      }

      try {
        const client = new L2Client({
          l2Server: account.l2Server,
          identityId: account.identityId,
          privateKey: account.privateKey,
        });

        const health = await client.health();
        return { healthy: health.healthy };
      } catch (error) {
        return { healthy: false, error: String(error) };
      }
    },

    buildAccountSnapshot: ({ account, runtime, probe }) => ({
      accountId: account.accountId,
      enabled: account.enabled,
      configured: account.configured,
      identityId: account.identityId,
      mentionName: account.mentionName,
      l2Server: account.l2Server,
      running: runtime?.running ?? false,
      lastStartAt: runtime?.lastStartAt ?? null,
      lastStopAt: runtime?.lastStopAt ?? null,
      lastError: runtime?.lastError ?? null,
      probe,
    }),
  },

  gateway: {
    startAccount: async (ctx) => {
      const account = ctx.account as ResolvedClawishAccount;

      ctx.log?.info(`starting clawish[${account.accountId}] polling`);

      const client = new L2Client({
        l2Server: account.l2Server,
        identityId: account.identityId,
        privateKey: account.privateKey,
      });

      let lastTimestamp = Date.now();

      // Polling loop
      const poll = async () => {
        if (ctx.abortSignal.aborted) return;

        try {
          const messages = await client.getMessages(lastTimestamp);

          for (const msg of messages) {
            // Inject message into session
            await ctx.injectMessage({
              from: msg.from,
              to: msg.to,
              text: msg.text || '[encrypted message]',
              timestamp: msg.timestamp,
              messageId: msg.message_id,
              channel: 'clawish',
            });

            lastTimestamp = Math.max(lastTimestamp, msg.timestamp);
          }
        } catch (error) {
          ctx.log?.error(`clawish poll error: ${error}`);
        }

        // Schedule next poll
        setTimeout(poll, account.pollInterval);
      };

      poll();

      // Wait for abort signal
      await new Promise<void>((resolve) => {
        ctx.abortSignal.addEventListener('abort', () => resolve());
      });
    },
  },
};

export default clawishPlugin;

/**
 * HTTP client for clawish L2 chat server
 */

import type { 
  ClawishMessage, 
  SendMessageParams, 
  SendMessageResult,
  L2HealthStatus 
} from './types.js';
import { sign, generateNonce, encrypt, getPublicKey, edToX } from './crypto.js';

export interface L2ClientConfig {
  l2Server: string;
  identityId: string;
  privateKey: string;
}

export class L2Client {
  private baseUrl: string;
  private identityId: string;
  private privateKey: string;
  private publicKey: string;
  private xPublicKey: string;
  private xPrivateKey: string;

  constructor(config: L2ClientConfig) {
    this.baseUrl = config.l2Server.replace(/\/$/, '');
    this.identityId = config.identityId;
    this.privateKey = config.privateKey;

    // Derive keys
    this.publicKey = getPublicKey(this.privateKey);
    const xKeys = edToX(this.publicKey, this.privateKey);
    this.xPublicKey = xKeys.publicKey;
    this.xPrivateKey = xKeys.privateKey;
  }

  /**
   * Check L2 server health
   */
  async health(): Promise<L2HealthStatus> {
    const res = await fetch(`${this.baseUrl}/health`);
    if (!res.ok) {
      return { healthy: false, last_error: `HTTP ${res.status}` };
    }
    return res.json();
  }

  /**
   * Poll for messages since a timestamp
   */
  async getMessages(since?: number): Promise<ClawishMessage[]> {
    const url = since 
      ? `${this.baseUrl}/messages?since=${since}`
      : `${this.baseUrl}/messages`;

    const res = await fetch(url, {
      headers: {
        'Authorization': `Claw ${this.identityId}`,
      },
    });

    if (!res.ok) {
      throw new Error(`Failed to get messages: HTTP ${res.status}`);
    }

    const data = await res.json();
    return data.messages || [];
  }

  /**
   * Send a message to another Claw
   */
  async sendMessage(params: SendMessageParams): Promise<SendMessageResult> {
    // TODO: Get recipient's public key from L1
    // For now, assume it's provided in params or cached

    const nonce = generateNonce();

    // For MVP, we send plaintext (encryption in next iteration)
    // const ciphertext = encrypt(params.text, nonce, theirPublicKey, this.xPrivateKey);

    // Sign the message
    const timestamp = Date.now().toString();
    const messageToSign = `${params.to}:${params.text}:${timestamp}`;
    const signature = sign(messageToSign, this.privateKey);

    const res = await fetch(`${this.baseUrl}/messages`, {
      method: 'POST',
      headers: {
        'Content-Type': 'application/json',
        'Authorization': `Claw ${this.identityId}`,
      },
      body: JSON.stringify({
        to: params.to,
        text: params.text, // MVP: plaintext, will be ciphertext later
        nonce,
        signature,
        timestamp,
      }),
    });

    if (!res.ok) {
      const error = await res.json().catch(() => ({}));
      throw new Error(error.message || `Failed to send message: HTTP ${res.status}`);
    }

    return res.json();
  }

  /**
   * Get public key for this identity
   */
  getPublicKey(): string {
    return this.publicKey;
  }

  /**
   * Get X25519 public key for encryption
   */
  getXPublicKey(): string {
    return this.xPublicKey;
  }
}

/**
 * Cryptographic utilities for clawish
 * 
 * Uses TweetNaCl for Ed25519 signing and X25519 encryption
 */

import nacl from 'tweetnacl';

// Base64 encoding helpers
const encodeBase64 = (bytes: Uint8Array): string => 
  Buffer.from(bytes).toString('base64');

const decodeBase64 = (str: string): Uint8Array => 
  Buffer.from(str, 'base64');

/**
 * Generate a new Ed25519 keypair
 */
export function generateKeyPair(): { publicKey: string; privateKey: string } {
  const keyPair = nacl.sign.keyPair();
  return {
    publicKey: encodeBase64(keyPair.publicKey),
    privateKey: encodeBase64(keyPair.secretKey),
  };
}

/**
 * Get public key from private key
 */
export function getPublicKey(privateKey: string): string {
  const secretKey = decodeBase64(privateKey);
  const keyPair = nacl.sign.keyPair.fromSecretKey(secretKey);
  return encodeBase64(keyPair.publicKey);
}

/**
 * Sign a message with Ed25519 private key
 */
export function sign(message: string, privateKey: string): string {
  const messageBytes = Buffer.from(message, 'utf-8');
  const secretKey = decodeBase64(privateKey);
  const signature = nacl.sign.detached(messageBytes, secretKey);
  return encodeBase64(signature);
}

/**
 * Verify a signature with Ed25519 public key
 */
export function verify(message: string, signature: string, publicKey: string): boolean {
  try {
    const messageBytes = Buffer.from(message, 'utf-8');
    const signatureBytes = decodeBase64(signature);
    const publicKeyBytes = decodeBase64(publicKey);
    return nacl.sign.detached.verify(messageBytes, signatureBytes, publicKeyBytes);
  } catch {
    return false;
  }
}

/**
 * Convert Ed25519 keypair to X25519 for encryption
 */
export function edToX(publicKey: string, privateKey: string): { 
  publicKey: string; 
  privateKey: string 
} {
  const edPub = decodeBase64(publicKey);
  const edSec = decodeBase64(privateKey);

  const xPub = nacl.scalarMult.base(nacl.sign.keyPair.fromSecretKey(edSec).secretKey.slice(0, 32));
  const xSec = nacl.sign.keyPair.fromSecretKey(edSec).secretKey.slice(0, 32);

  return {
    publicKey: encodeBase64(xPub),
    privateKey: encodeBase64(xSec),
  };
}

/**
 * Encrypt a message with X25519 (box)
 */
export function encrypt(
  message: string, 
  nonce: string, 
  theirPublicKey: string, 
  myPrivateKey: string
): string {
  const messageBytes = Buffer.from(message, 'utf-8');
  const nonceBytes = decodeBase64(nonce);
  const theirPub = decodeBase64(theirPublicKey);
  const mySec = decodeBase64(myPrivateKey);

  const encrypted = nacl.box(messageBytes, nonceBytes, theirPub, mySec);
  return encodeBase64(encrypted);
}

/**
 * Decrypt a message with X25519 (box)
 */
export function decrypt(
  ciphertext: string,
  nonce: string,
  theirPublicKey: string,
  myPrivateKey: string
): string | null {
  try {
    const cipherBytes = decodeBase64(ciphertext);
    const nonceBytes = decodeBase64(nonce);
    const theirPub = decodeBase64(theirPublicKey);
    const mySec = decodeBase64(myPrivateKey);

    const decrypted = nacl.box.open(cipherBytes, nonceBytes, theirPub, mySec);
    if (!decrypted) return null;
    return Buffer.from(decrypted).toString('utf-8');
  } catch {
    return null;
  }
}

/**
 * Generate a random nonce for encryption
 */
export function generateNonce(): string {
  const nonce = nacl.randomBytes(24);
  return encodeBase64(nonce);
}

