+372     return { valid: true, brokenAt: null, entriesChecked: 0 };
+373   }
+374   
+375   // Verify each entry's hash chain
+376   for (let i = 0; i < entries.length; i++) {
+377     const entry = entries[i];
+378     
+379     // Recompute hash
+380     const computedHash = computeHash({
+381       ledger_id: entry.ledger_id,
+382       identity_id: entry.identity_id,
+383       action: entry.action,
+384       payload: entry.payload,
+385       signature: entry.signature,
+386       previous_hash: entry.previous_hash,
+387       timestamp: entry.timestamp,
+388     });
+389     
+390     // Check hash matches
+391     if (computedHash !== entry.current_hash) {
+392       return { valid: false, brokenAt: entry.ledger_id, entriesChecked: i };
+393     }
+394     
+395     // Check chain linkage (except genesis)
+396     if (i > 0) {
+397       const expectedPreviousHash = entries[i - 1].current_hash;
+398       if (entry.previous_hash !== expectedPreviousHash) {
+399         return { valid: false, brokenAt: entry.ledger_id, entriesChecked: i };
+400       }
+401     }
+402   }
+403   
+404   return { valid: true, brokenAt: null, entriesChecked: entries.length };
+405 }
+406 
+407 /**
+408  * Rebuild clawfile state from ledger history
+409  * This proves that state tables are derived, not primary
+410  */
+411 export function rebuildFromLedgers(db: Database.Database, identityId: string): Partial<Clawfile> | null {
+412   const entries = getLedgerHistory(db, identityId);
+413   
+414   if (entries.length === 0) {
+415     return null;
+416   }
+417   
+418   // Start with empty state
+419   const state: Partial<Clawfile> = {
+420     identity_id: identityId,
+421   };
+422   
+423   // Apply each event in order
+424   for (const entry of entries) {
+425     const payload = JSON.parse(entry.payload);
+426     
+427     switch (entry.action) {
+428       case 'identity.created':
+429         Object.assign(state, {
+430           public_key: payload.public_key,
+431           mention_name: payload.mention_name,
+432           display_name: payload.display_name,
+433           human_parent: payload.human_parent,
+434           bio: payload.bio,
+435           principles: payload.principles,
+436           avatar_url: payload.avatar_url,
+437           verification_tier: 0,
+438           status: 'active',
+439           created_at: entry.timestamp,
+440           updated_at: entry.timestamp,
+441         });
+442         break;
+443         
+444       case 'profile.updated':
+445         Object.assign(state, payload);
+446         state.updated_at = entry.timestamp;
+447         break;
+448         
+449       case 'key.added':
+450         // For multi-key model (future)
+451         break;
+452         
+453       case 'key.archived':
+454         // For multi-key model (future)
+455         break;
+456         
+457       case 'verification.granted':
+458         state.verification_tier = payload.tier;
+459         state.updated_at = entry.timestamp;
+460         break;
+461         
+462       case 'status.changed':
+463         state.status = payload.status;
+464         state.updated_at = entry.timestamp;
+465         break;
+466     }
+467   }
+468   
+469   return state;
+470 }

