/**
 * Node registry routes - L1 node discovery and registration
 */

import { Hono } from 'hono';
import { z } from 'zod';
import Database from 'better-sqlite3';
import { ulid } from 'ulid';
import { createHash } from 'crypto';

// Node types
export interface NodeRecord {
  node_id: string;
  public_key: string;
  fingerprint: string;
  endpoint: string;
  type: 'writer' | 'query';
  status: 'probation' | 'active' | 'inactive';
  registered_at: number;
  last_seen_at: number | null;
  sync_speed_ms: number | null;
}

// Validation schemas
const registerNodeSchema = z.object({
  public_key: z.string().min(1),
  endpoint: z.string().url(),
});

export function nodeRoutes(db: Database.Database) {
  const app = new Hono();

  // Initialize nodes table if not exists
  db.exec(`
    CREATE TABLE IF NOT EXISTS nodes (
      node_id TEXT PRIMARY KEY,
      public_key TEXT NOT NULL UNIQUE,
      fingerprint TEXT NOT NULL UNIQUE,
      endpoint TEXT NOT NULL,
      type TEXT DEFAULT 'query',
      status TEXT DEFAULT 'probation',
      registered_at INTEGER NOT NULL,
      last_seen_at INTEGER,
      sync_speed_ms INTEGER
    );

    CREATE INDEX IF NOT EXISTS idx_nodes_public_key ON nodes(public_key);
    CREATE INDEX IF NOT EXISTS idx_nodes_status ON nodes(status);
    CREATE INDEX IF NOT EXISTS idx_nodes_type ON nodes(type);
  `);

  // GET /nodes - List active nodes (Node Query Endpoint)
  app.get('/', (c) => {
    const status = c.req.query('status') || 'active';
    const type = c.req.query('type');

    let sql = 'SELECT node_id, fingerprint, endpoint, type, status, registered_at FROM nodes WHERE status = ?';
    const params: string[] = [status];

    if (type) {
      sql += ' AND type = ?';
      params.push(type);
    }

    sql += ' ORDER BY sync_speed_ms ASC NULLS LAST';

    const stmt = db.prepare(sql);
    const nodes = stmt.all(...params) as Partial<NodeRecord>[];

    return c.json({
      nodes: nodes.map(n => ({
        endpoint: n.endpoint,
        type: n.type,
        status: n.status,
        fingerprint: n.fingerprint,
      })),
      count: nodes.length,
    });
  });

  // GET /nodes/:id - Get node by ID or fingerprint
  app.get('/:id', (c) => {
    const id = c.req.param('id');

    const stmt = db.prepare(`
      SELECT node_id, public_key, fingerprint, endpoint, type, status, registered_at, last_seen_at, sync_speed_ms
      FROM nodes 
      WHERE node_id = ? OR fingerprint = ?
    `);

    const node = stmt.get(id, id) as NodeRecord | undefined;

    if (!node) {
      return c.json({ error: 'not_found', message: 'node not found' }, 404);
    }

    return c.json(node);
  });

  // POST /nodes/register - Register new node
  app.post('/register', async (c) => {
    try {
      const body = await c.req.json();
      const parsed = registerNodeSchema.safeParse(body);

      if (!parsed.success) {
        return c.json({ error: 'invalid_request', details: parsed.error.errors }, 400);
      }

      const { public_key, endpoint } = parsed.data;

      // Check if public_key already registered
      const existing = db.prepare('SELECT node_id FROM nodes WHERE public_key = ?').get(public_key);
      if (existing) {
        return c.json({ error: 'conflict', message: 'public_key already registered' }, 409);
      }

      // Generate node_id and fingerprint
      const nodeId = ulid();
      const fingerprint = createHash('sha256').update(public_key).digest('hex').slice(0, 16);
      const now = Date.now();

      // Insert node
      const stmt = db.prepare(`
        INSERT INTO nodes (node_id, public_key, fingerprint, endpoint, type, status, registered_at)
        VALUES (?, ?, ?, ?, 'query', 'probation', ?)
      `);

      stmt.run(nodeId, public_key, fingerprint, endpoint, now);

      return c.json({
        node_id: nodeId,
        fingerprint,
        endpoint,
        type: 'query',
        status: 'probation',
        message: 'Node registered. 90-day probation period begins.',
        registered_at: now,
      }, 201);

    } catch (error) {
      console.error('Register node error:', error);
      return c.json({ error: 'internal_error' }, 500);
    }
  });

  // POST /nodes/:id/heartbeat - Update last_seen_at
  app.post('/:id/heartbeat', (c) => {
    const id = c.req.param('id');
    const node = db.prepare('SELECT node_id FROM nodes WHERE node_id = ? OR fingerprint = ?').get(id, id);

    if (!node) {
      return c.json({ error: 'not_found', message: 'node not found' }, 404);
    }

    const now = Date.now();
    db.prepare('UPDATE nodes SET last_seen_at = ? WHERE node_id = ?').run(now, (node as any).node_id);

    return c.json({ ok: true, last_seen_at: now });
  });

  // GET /nodes/:id/metrics - Get node performance metrics
  app.get('/:id/metrics', (c) => {
    const id = c.req.param('id');

    const node = db.prepare(`
      SELECT node_id, type, status, sync_speed_ms, last_seen_at, registered_at
      FROM nodes 
      WHERE node_id = ? OR fingerprint = ?
    `).get(id, id) as NodeRecord | undefined;

    if (!node) {
      return c.json({ error: 'not_found', message: 'node not found' }, 404);
    }

    const now = Date.now();
    const ageMs = now - node.registered_at;
    const ageDays = Math.floor(ageMs / (1000 * 60 * 60 * 24));
    const probationComplete = ageDays >= 90;

    return c.json({
      node_id: node.node_id,
      type: node.type,
      status: node.status,
      sync_speed_ms: node.sync_speed_ms,
      last_seen_at: node.last_seen_at,
      age_days: ageDays,
      probation_complete: probationComplete,
      eligible_for_writer: probationComplete && node.status === 'active' && node.type === 'query',
    });
  });

  return app;
}

