/**
 * Signature verification middleware for L1
 * 
 * All mutating operations must be signed by the identity's private key.
 * This middleware extracts and verifies signatures from requests.
 */

import { Context, Next } from 'hono';
import { createHash } from 'crypto';
import * as nacl from 'tweetnacl';

// Base64 helpers
const decodeBase64 = (str: string): Uint8Array => Buffer.from(str, 'base64');
const encodeHex = (bytes: Uint8Array): string => Buffer.from(bytes).toString('hex');

/**
 * Verify an Ed25519 signature
 */
export function verifySignature(
  message: string,
  signature: string,
  publicKey: string
): boolean {
  try {
    const messageBytes = Buffer.from(message, 'utf-8');
    const signatureBytes = decodeBase64(signature);
    const publicKeyBytes = decodeBase64(publicKey);

    return nacl.sign.detached.verify(messageBytes, signatureBytes, publicKeyBytes);
  } catch (error) {
    console.error('Signature verification error:', error);
    return false;
  }
}

/**
 * Create a canonical message to sign from request data
 * This ensures consistent signing across different clients
 */
export function createSignMessage(
  action: string,
  data: Record<string, any>,
  timestamp: number
): string {
  // Sort keys for canonical representation
  const sortedData = Object.keys(data)
    .sort()
    .map(k => `${k}=${JSON.stringify(data[k])}`)
    .join('&');

  return `${action}:${timestamp}:${sortedData}`;
}

/**
 * Middleware to verify signature on mutating requests
 * 
 * Expects headers:
 * - X-Identity-Id: The identity making the request
 * - X-Timestamp: Unix timestamp in milliseconds (must be within ±5 minutes)
 * - X-Signature: Ed25519 signature (base64)
 */
export async function verifySignatureMiddleware(
  c: Context,
  next: Next,
  options?: {
    getPublicKey?: (identityId: string) => Promise<string | null>;
    requireSignature?: boolean;
  }
) {
  const requireSignature = options?.requireSignature ?? true;

  // Only check mutating methods
  const method = c.req.method;
  if (!['POST', 'PATCH', 'PUT', 'DELETE'].includes(method)) {
    return next();
  }

  // Get signature headers
  const identityId = c.req.header('X-Identity-Id');
  const timestamp = c.req.header('X-Timestamp');
  const signature = c.req.header('X-Signature');

  // Check required headers
  if (!identityId || !timestamp || !signature) {
    if (requireSignature) {
      return c.json({
        error: 'unauthorized',
        message: 'Missing signature headers (X-Identity-Id, X-Timestamp, X-Signature)',
      }, 401);
    }
    return next();
  }

  // Validate timestamp (±5 minutes)
  const now = Date.now();
  const requestTime = parseInt(timestamp, 10);
  const drift = Math.abs(now - requestTime);
  const maxDrift = 5 * 60 * 1000; // 5 minutes

  if (isNaN(requestTime) || drift > maxDrift) {
    return c.json({
      error: 'invalid_timestamp',
      message: `Timestamp must be within ±5 minutes. Drift: ${Math.floor(drift / 1000)}s`,
    }, 401);
  }

  // Get public key
  let publicKey: string | null = null;

  if (options?.getPublicKey) {
    publicKey = await options.getPublicKey(identityId);
  }

  if (!publicKey) {
    return c.json({
      error: 'identity_not_found',
      message: 'Could not find public key for identity',
    }, 401);
  }

  // Read request body
  const body = await c.req.json();

  // Store body for later use (since we consumed it)
  c.set('requestBody', body);

  // Create canonical message
  const action = c.req.path;
  const message = createSignMessage(action, body, requestTime);

  // Verify signature
  if (!verifySignature(message, signature, publicKey)) {
    return c.json({
      error: 'invalid_signature',
      message: 'Signature verification failed',
    }, 401);
  }

  // Signature valid, continue
  return next();
}

/**
 * Helper to get request body (set by middleware)
 */
export function getRequestBody<T>(c: Context): T {
  return c.get('requestBody') as T;
}

/**
 * Challenge-response authentication for initial registration
 * When identity doesn't exist yet, we verify key ownership differently
 */
export function verifyProofOfKeyOwnership(
  publicKey: string,
  proof: {
    signature: string;
    timestamp: string;
    nonce?: string;
  }
): boolean {
  // Create message to verify
  const message = proof.nonce 
    ? `register:${proof.timestamp}:${proof.nonce}`
    : `register:${proof.timestamp}`;

  return verifySignature(message, proof.signature, publicKey);
}

/**
 * Generate a challenge for key ownership proof
 */
export function generateChallenge(): { nonce: string; expiresAt: number } {
  const nonce = createHash('sha256')
    .update(Date.now().toString() + Math.random().toString())
    .digest('hex')
    .slice(0, 32);

  const expiresAt = Date.now() + 10 * 60 * 1000; // 10 minutes

  return { nonce, expiresAt };
}

