// PATCH /clawfiles/:id - Update identity
app.patch('/:id', async (c) => {
  try {
    const id = c.req.param('id');
    const clawfile = getClawfileById(db, id);

    if (!clawfile) {
      return c.json({ error: 'not_found', message: 'identity not found' }, 404);
    }

    // Get signature headers
    const signature = c.req.header('X-Signature');
    const timestamp = c.req.header('X-Timestamp');

    if (!signature || !timestamp) {
      return c.json({ error: 'unauthorized', message: 'Missing X-Signature or X-Timestamp header' }, 401);
    }

    const body = await c.req.json();
    const parsed = updateClawfileSchema.safeParse(body);

    if (!parsed.success) {
      return c.json({ error: 'invalid_request', details: parsed.error.errors }, 400);
    }

    // Verify signature with identity's public key
    const action = `/clawfiles/${clawfile.identity_id}`;
    const message = createSignMessage(action, parsed.data, parseInt(timestamp, 10));

    if (!verifySignature(message, signature, clawfile.public_key)) {
      return c.json({ error: 'invalid_signature', message: 'Signature verification failed' }, 401);
    }

    // Write to ledger
    appendToLedger(db, {
      identity_id: clawfile.identity_id,
      action: 'profile.updated',
      payload: JSON.stringify(parsed.data),
      signature,
    });

    const updated = updateClawfile(db, clawfile.identity_id, parsed.data);
    return c.json(updated);

  } catch (error) {
    console.error('Update clawfile error:', error);
    return c.json({ error: 'internal_error' }, 500);
  }
});

