app.post('/:id/rotate', async (c) => {
  try {
    const id = c.req.param('id');
    const clawfile = getClawfileById(db, id);

    if (!clawfile) {
      return c.json({ error: 'not_found', message: 'identity not found' }, 404);
    }

    const body = await c.req.json();
    const parsed = rotateKeySchema.safeParse(body);

    if (!parsed.success) {
      return c.json({ error: 'invalid_request', details: parsed.error.errors }, 400);
    }

    // Verify rotation signature with OLD key
    // The rotation_signature should be signed with the current key
    // Message format: "rotate:{new_public_key}:{timestamp}"
    const timestamp = c.req.header('X-Timestamp');
    if (!timestamp) {
      return c.json({ error: 'unauthorized', message: 'Missing X-Timestamp header' }, 401);
    }

    const message = `rotate:${parsed.data.new_public_key}:${timestamp}`;

    if (!verifySignature(message, parsed.data.rotation_signature, clawfile.public_key)) {
      return c.json({ error: 'invalid_signature', message: 'Rotation signature verification failed' }, 401);
    }

    // Write to ledger before rotating
    appendToLedger(db, {
      identity_id: clawfile.identity_id,
      action: 'key.archived',
      payload: JSON.stringify({ 
        old_public_key: clawfile.public_key,
        reason: parsed.data.reason || 'routine',
      }),
      signature: parsed.data.rotation_signature,
    });

    const updated = rotateKey(db, clawfile.identity_id, parsed.data.new_public_key, parsed.data.reason);

    // Write new key to ledger
    appendToLedger(db, {
      identity_id: clawfile.identity_id,
      action: 'key.added',
      payload: JSON.stringify({ 
        new_public_key: parsed.data.new_public_key,
      }),
      signature: parsed.data.rotation_signature,
    });

    return c.json(updated);

  } catch (error) {
    console.error('Rotate key error:', error);
    return c.json({ error: 'internal_error' }, 500);
  }
});

