/**
 * Tests for Ledger hash-chaining system
 */

import { describe, it, expect, beforeEach } from 'vitest';
import Database from 'better-sqlite3';
import { 
  initDb, 
  appendToLedger, 
  getLedgerHistory, 
  verifyLedgerChain,
  rebuildFromLedgers,
  type LedgerAction 
} from './index.js';

describe('Ledger System', () => {
  let db: Database.Database;

  beforeEach(() => {
    db = initDb(':memory:');
  });

  describe('appendToLedger', () => {
    it('should create genesis entry with null previous_hash', () => {
      const entry = appendToLedger(db, {
        identity_id: '01HQXYZ1234567890ABCDEF',
        action: 'identity.created',
        payload: JSON.stringify({ mention_name: 'alpha', display_name: 'Alpha' }),
        signature: 'test_signature_1',
      });

      expect(entry.identity_id).toBe('01HQXYZ1234567890ABCDEF');
      expect(entry.action).toBe('identity.created');
      expect(entry.previous_hash).toBeNull();
      expect(entry.current_hash).toMatch(/^[a-f0-9]{64}$/); // SHA-256 hex
    });

    it('should chain entries with previous_hash', () => {
      const entry1 = appendToLedger(db, {
        identity_id: '01HQXYZ1234567890ABCDEF',
        action: 'identity.created',
        payload: JSON.stringify({ mention_name: 'alpha' }),
        signature: 'sig1',
      });

      const entry2 = appendToLedger(db, {
        identity_id: '01HQXYZ1234567890ABCDEF',
        action: 'profile.updated',
        payload: JSON.stringify({ bio: 'First Claw' }),
        signature: 'sig2',
      });

      expect(entry2.previous_hash).toBe(entry1.current_hash);
      expect(entry2.current_hash).not.toBe(entry1.current_hash);
    });

    it('should compute deterministic hashes', () => {
      const entry1a = appendToLedger(db, {
        identity_id: '01HQXYZ1234567890ABCDEF',
        action: 'identity.created',
        payload: JSON.stringify({ name: 'alpha' }),
        signature: 'sig1',
      });

      // Clear and recreate
      db.exec('DELETE FROM ledgers');

      const entry1b = appendToLedger(db, {
        identity_id: '01HQXYZ1234567890ABCDEF',
        action: 'identity.created',
        payload: JSON.stringify({ name: 'alpha' }),
        signature: 'sig1',
      });

      // Hashes should be different because timestamp differs
      // But the hash computation should be deterministic for same data
      expect(entry1a.current_hash).toMatch(/^[a-f0-9]{64}$/);
      expect(entry1b.current_hash).toMatch(/^[a-f0-9]{64}$/);
    });
  });

  describe('getLedgerHistory', () => {
    it('should return empty array for unknown identity', () => {
      const history = getLedgerHistory(db, 'UNKNOWN_ID');
      expect(history).toEqual([]);
    });

    it('should return entries in chronological order', () => {
      appendToLedger(db, {
        identity_id: '01HQXYZ1234567890ABCDEF',
        action: 'identity.created',
        payload: JSON.stringify({ name: 'alpha' }),
        signature: 'sig1',
      });

      appendToLedger(db, {
        identity_id: '01HQXYZ1234567890ABCDEF',
        action: 'profile.updated',
        payload: JSON.stringify({ bio: 'test' }),
        signature: 'sig2',
      });

      appendToLedger(db, {
        identity_id: '01HQXYZ1234567890ABCDEF',
        action: 'key.added',
        payload: JSON.stringify({ key: 'new_key' }),
        signature: 'sig3',
      });

      const history = getLedgerHistory(db, '01HQXYZ1234567890ABCDEF');
      expect(history).toHaveLength(3);
      expect(history[0].action).toBe('identity.created');
      expect(history[1].action).toBe('profile.updated');
      expect(history[2].action).toBe('key.added');
    });

    it('should support pagination with since', () => {
      const entry1 = appendToLedger(db, {
        identity_id: '01HQXYZ1234567890ABCDEF',
        action: 'identity.created',
        payload: '{}',
        signature: 'sig1',
      });

      // Small delay to ensure different timestamp
      const entry2 = appendToLedger(db, {
        identity_id: '01HQXYZ1234567890ABCDEF',
        action: 'profile.updated',
        payload: '{}',
        signature: 'sig2',
      });

      const recent = getLedgerHistory(db, '01HQXYZ1234567890ABCDEF', { 
        since: entry1.timestamp + 1 
      });
      expect(recent).toHaveLength(1);
      expect(recent[0].action).toBe('profile.updated');
    });
  });

  describe('verifyLedgerChain', () => {
    it('should return valid for empty ledger', () => {
      const result = verifyLedgerChain(db, 'UNKNOWN_ID');
      expect(result.valid).toBe(true);
      expect(result.entriesChecked).toBe(0);
    });

    it('should verify correct chain', () => {
      appendToLedger(db, {
        identity_id: '01HQXYZ1234567890ABCDEF',
        action: 'identity.created',
        payload: '{}',
        signature: 'sig1',
      });

      appendToLedger(db, {
        identity_id: '01HQXYZ1234567890ABCDEF',
        action: 'profile.updated',
        payload: '{}',
        signature: 'sig2',
      });

      const result = verifyLedgerChain(db, '01HQXYZ1234567890ABCDEF');
      expect(result.valid).toBe(true);
      expect(result.entriesChecked).toBe(2);
      expect(result.brokenAt).toBeNull();
    });

    it('should detect tampered hash', () => {
      appendToLedger(db, {
        identity_id: '01HQXYZ1234567890ABCDEF',
        action: 'identity.created',
        payload: '{}',
        signature: 'sig1',
      });

      // Tamper with the hash
      db.prepare("UPDATE ledgers SET current_hash = 'tampered_hash' WHERE identity_id = ?")
        .run('01HQXYZ1234567890ABCDEF');

      const result = verifyLedgerChain(db, '01HQXYZ1234567890ABCDEF');
      expect(result.valid).toBe(false);
      expect(result.brokenAt).toBeTruthy();
    });

    it('should detect broken chain linkage', () => {
      appendToLedger(db, {
        identity_id: '01HQXYZ1234567890ABCDEF',
        action: 'identity.created',
        payload: '{}',
        signature: 'sig1',
      });

      appendToLedger(db, {
        identity_id: '01HQXYZ1234567890ABCDEF',
        action: 'profile.updated',
        payload: '{}',
        signature: 'sig2',
      });

      // Break the chain by modifying previous_hash
      db.prepare("UPDATE ledgers SET previous_hash = 'wrong_previous' WHERE action = 'profile.updated'")
        .run();

      const result = verifyLedgerChain(db, '01HQXYZ1234567890ABCDEF');
      expect(result.valid).toBe(false);
    });
  });

  describe('rebuildFromLedgers', () => {
    it('should return null for empty ledger', () => {
      const state = rebuildFromLedgers(db, 'UNKNOWN_ID');
      expect(state).toBeNull();
    });

    it('should rebuild identity state from events', () => {
      appendToLedger(db, {
        identity_id: '01HQXYZ1234567890ABCDEF',
        action: 'identity.created',
        payload: JSON.stringify({
          public_key: 'key123',
          mention_name: 'alpha',
          display_name: 'Alpha',
          bio: 'First Claw',
        }),
        signature: 'sig1',
      });

      appendToLedger(db, {
        identity_id: '01HQXYZ1234567890ABCDEF',
        action: 'profile.updated',
        payload: JSON.stringify({
          display_name: 'Claw Alpha',
          bio: 'First of the Clawish',
        }),
        signature: 'sig2',
      });

      appendToLedger(db, {
        identity_id: '01HQXYZ1234567890ABCDEF',
        action: 'verification.granted',
        payload: JSON.stringify({ tier: 1 }),
        signature: 'sig3',
      });

      const state = rebuildFromLedgers(db, '01HQXYZ1234567890ABCDEF');

      expect(state).toBeTruthy();
      expect(state?.mention_name).toBe('alpha');
      expect(state?.display_name).toBe('Claw Alpha'); // Updated
      expect(state?.bio).toBe('First of the Clawish'); // Updated
      expect(state?.verification_tier).toBe(1);
      expect(state?.status).toBe('active');
    });
  });
});

